import { DndContext } from '@dnd-kit/core';
import { useState } from 'react';

function Board() {
  const [activeId, setActiveId] = useState(null);

  function handleDragStart(event) {
    const target = event.activatorEvent.target;
    // Kiểm tra phần tử được click hoặc cha của nó có thuộc tính data-no-dnd không
    if (target.closest('[data-no-dnd="true"]')) {
      // Nếu có, không làm gì cả để ngăn việc kéo
      // Quan trọng: phải có cách để hủy bỏ việc kéo, trong trường hợp này, không set activeId là một cách.
      // Một cách tiếp cận khác là tạo một sensor tùy chỉnh.
      return;
    }
    console.log("Drag started!");
    setActiveId(event.active.id);
  }

  return (
    <DndContext onDragStart={handleDragStart}>
      {/* ... */}
    </DndContext>
  );
}
